import jsonStringify from"fastest-stable-stringify";import*as Browser from"@hyperjump/browser";import*as Instance from"../instance.js";const id="https://json-schema.org/keyword/uniqueItems",compile=e=>Browser.value(e),interpret=(e,r)=>{if("array"!==Instance.typeOf(r)||!1===e)return!0;e=Instance.value(r).map(jsonStringify);return new Set(e).size===e.length};export default{id:id,compile:compile,interpret:interpret};